"use client";

import { useMemo, useState } from "react";
import { Card, Button, Badge } from "@/components/marketing/ui";
import {
  EXAMS,
  getExam,
  bandFor,
  type Exam,
  type Question,
} from "@/lib/marketing-tests/exams";

type Phase = "picker" | "running" | "results";

interface AnswerRecord {
  questionId: string;
  selected: number;
  correct: number;
  skill: string;
  difficulty: number;
  isCorrect: boolean;
}

interface ExamResult {
  examId: string;
  score: number;
  total: number;
  correctCount: number;
  percentage: number;
  passed: boolean;
  band: ReturnType<typeof bandFor>;
  skillBreakdown: Record<string, { correct: number; total: number; pct: number }>;
  answers: AnswerRecord[];
  candidate: string;
  elapsedSeconds: number;
}

function shuffle<T>(arr: T[]): T[] {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j]!, a[i]!];
  }
  return a;
}

function gradeColor(percentage: number): string {
  if (percentage >= 85) return "bg-green-100 text-green-800 border-green-200";
  if (percentage >= 70) return "bg-blue-100 text-blue-800 border-blue-200";
  if (percentage >= 50) return "bg-amber-100 text-amber-800 border-amber-200";
  return "bg-red-100 text-red-800 border-red-200";
}

export function MarketingTests() {
  const [phase, setPhase] = useState<Phase>("picker");
  const [activeExam, setActiveExam] = useState<Exam | null>(null);
  const [shuffled, setShuffled] = useState<Question[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [answers, setAnswers] = useState<Record<string, number>>({});
  const [candidate, setCandidate] = useState("");
  const [result, setResult] = useState<ExamResult | null>(null);
  const [startTime, setStartTime] = useState(0);

  const startExam = (exam: Exam) => {
    setActiveExam(exam);
    setShuffled(shuffle(exam.questions));
    setCurrentIdx(0);
    setAnswers({});
    setResult(null);
    setStartTime(Date.now());
    setPhase("running");
  };

  const selectAnswer = (questionId: string, optionIdx: number) => {
    setAnswers((prev) => ({ ...prev, [questionId]: optionIdx }));
  };

  const computeResult = (): ExamResult => {
    if (!activeExam) throw new Error("no active exam");
    const breakdown: Record<string, { correct: number; total: number; pct: number }> = {};
    const records: AnswerRecord[] = [];
    let correctCount = 0;
    for (const q of shuffled) {
      const selected = answers[q.id];
      const isCorrect = selected === q.correct;
      if (isCorrect) correctCount++;
      records.push({
        questionId: q.id,
        selected: selected ?? -1,
        correct: q.correct,
        skill: q.skill,
        difficulty: q.difficulty,
        isCorrect,
      });
      if (!breakdown[q.skill]) breakdown[q.skill] = { correct: 0, total: 0, pct: 0 };
      breakdown[q.skill]!.total += 1;
      if (isCorrect) breakdown[q.skill]!.correct += 1;
    }
    for (const k of Object.keys(breakdown)) {
      const b = breakdown[k]!;
      b.pct = Math.round((b.correct / b.total) * 100);
    }
    const total = shuffled.length;
    const percentage = Math.round((correctCount / total) * 100);
    return {
      examId: activeExam.id,
      score: correctCount,
      total,
      correctCount,
      percentage,
      passed: percentage >= activeExam.passingScore,
      band: bandFor(percentage),
      skillBreakdown: breakdown,
      answers: records,
      candidate: candidate.trim() || "Anonymous Candidate",
      elapsedSeconds: Math.round((Date.now() - startTime) / 1000),
    };
  };

  const submitExam = () => {
    setResult(computeResult());
    setPhase("results");
  };

  const restart = () => {
    setPhase("picker");
    setActiveExam(null);
    setShuffled([]);
    setAnswers({});
    setResult(null);
    setCandidate("");
  };

  const answeredCount = Object.keys(answers).length;
  const allAnswered = activeExam ? answeredCount >= shuffled.length : false;

  if (phase === "picker") {
    return <ExamPicker onPick={startExam} />;
  }

  if (phase === "results" && result) {
    return <ResultView result={result} exam={getExam(result.examId)} onRestart={restart} />;
  }

  if (!activeExam) return null;
  const q = shuffled[currentIdx]!;
  const selected = answers[q.id];
  const progress = Math.round((answeredCount / shuffled.length) * 100);

  return (
    <div className="space-y-6">
      <Card className="p-6">
        <div className="flex items-center justify-between flex-wrap gap-3">
          <div>
            <div className="flex items-center gap-2">
              <h2 className="text-xl font-bold text-gray-900">{activeExam.title}</h2>
              <Badge variant="secondary">{activeExam.level}</Badge>
            </div>
            <p className="text-sm text-gray-500 mt-1">
              Question {currentIdx + 1} of {shuffled.length} · {answeredCount}/{shuffled.length} answered
            </p>
          </div>
          <div className="text-right">
            <div className="text-xs text-gray-500">Passing score</div>
            <div className="text-lg font-bold text-gray-900">{activeExam.passingScore}%</div>
          </div>
        </div>
        <div className="mt-4 h-2 bg-gray-100 rounded-full overflow-hidden">
          <div
            className="h-full bg-indigo-600 transition-all"
            style={{ width: `${progress}%` }}
          />
        </div>
      </Card>

      <Card className="p-6">
        <div className="mb-3 flex items-center gap-2">
          <Badge variant="outline">{activeExam.domain}</Badge>
          <Badge variant="secondary">Skill: {q.skill}</Badge>
          <Badge variant="outline">
            {q.difficulty === 1 ? "Easy" : q.difficulty === 2 ? "Medium" : "Hard"}
          </Badge>
        </div>
        <p className="text-lg font-semibold text-gray-900 mb-4">{q.prompt}</p>
        <div className="space-y-2">
          {q.options.map((opt, idx) => {
            const active = selected === idx;
            return (
              <button
                key={idx}
                onClick={() => selectAnswer(q.id, idx)}
                className={`w-full text-left p-3 rounded-lg border transition-colors ${
                  active
                    ? "border-indigo-500 bg-indigo-50"
                    : "border-gray-200 hover:border-indigo-300 hover:bg-gray-50"
                }`}
              >
                <span className="font-medium mr-2 text-indigo-600">
                  {String.fromCharCode(65 + idx)}.
                </span>
                <span className="text-sm text-gray-800">{opt}</span>
              </button>
            );
          })}
        </div>
      </Card>

      <div className="flex items-center justify-between flex-wrap gap-3">
        <Button
          variant="outline"
          onClick={() => setCurrentIdx((i) => Math.max(0, i - 1))}
          disabled={currentIdx === 0}
        >
          Previous
        </Button>
        <div className="flex gap-1 flex-wrap max-w-full">
          {shuffled.map((sq, idx) => {
            const answered = answers[sq.id] !== undefined;
            const isCurrent = idx === currentIdx;
            return (
              <button
                key={sq.id}
                onClick={() => setCurrentIdx(idx)}
                className={`w-8 h-8 rounded-md text-xs font-medium transition-colors ${
                  isCurrent
                    ? "bg-indigo-600 text-white"
                    : answered
                      ? "bg-indigo-100 text-indigo-700"
                      : "bg-gray-100 text-gray-500 hover:bg-gray-200"
                }`}
                aria-label={`Go to question ${idx + 1}`}
              >
                {idx + 1}
              </button>
            );
          })}
        </div>
        {currentIdx < shuffled.length - 1 ? (
          <Button onClick={() => setCurrentIdx((i) => Math.min(shuffled.length - 1, i + 1))}>
            Next
          </Button>
        ) : (
          <Button onClick={submitExam} disabled={!allAnswered}>
            {allAnswered ? "Submit Exam" : `Answer all (${answeredCount}/${shuffled.length})`}
          </Button>
        )}
      </div>
    </div>
  );
}

function ExamPicker({ onPick }: { onPick: (e: Exam) => void }) {
  return (
    <div className="space-y-6">
      <Card className="p-6">
        <h2 className="text-xl font-bold text-gray-900">Marketing Professional Exams</h2>
        <p className="text-sm text-gray-600 mt-1">
          Recruiting-grade assessments across six marketing disciplines. Each exam is timed,
          skill-tagged, and scored against professional benchmarks with per-skill breakdowns
          for hiring decisions.
        </p>
        <div className="mt-4 grid grid-cols-2 sm:grid-cols-4 gap-3 text-center">
          <Stat label="Exams" value={EXAMS.length} />
          <Stat label="Questions" value={EXAMS.reduce((n, e) => n + e.questions.length, 0)} />
          <Stat label="Domains" value={new Set(EXAMS.map((e) => e.domain)).size} />
          <Stat label="Levels" value={new Set(EXAMS.map((e) => e.level)).size} />
        </div>
      </Card>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {EXAMS.map((exam) => (
          <Card key={exam.id} className="p-5 flex flex-col">
            <div className="flex items-center justify-between mb-2">
              <Badge variant="secondary">{exam.domain}</Badge>
              <Badge variant="outline">{exam.level}</Badge>
            </div>
            <h3 className="text-lg font-bold text-gray-900">{exam.title}</h3>
            <p className="text-sm text-gray-600 mt-2 flex-1">{exam.description}</p>
            <div className="mt-4 grid grid-cols-3 gap-2 text-center text-xs">
              <MiniStat label="Questions" value={exam.questions.length} />
              <MiniStat label="Minutes" value={exam.durationMinutes} />
              <MiniStat label="Pass" value={`${exam.passingScore}%`} />
            </div>
            <Button className="mt-4 w-full" onClick={() => onPick(exam)}>
              Start Exam
            </Button>
          </Card>
        ))}
      </div>
    </div>
  );
}

function ResultView({
  result,
  exam,
  onRestart,
}: {
  result: ExamResult;
  exam?: Exam;
  onRestart: () => void;
}) {
  const skills = useMemo(
    () =>
      Object.entries(result.skillBreakdown).sort((a, b) => b[1].pct - a[1].pct),
    [result],
  );

  return (
    <div className="space-y-6">
      <Card className="p-6">
        <div className="flex items-center justify-between flex-wrap gap-3">
          <div>
            <div className="text-xs uppercase tracking-wider text-gray-500">
              Recruiting Report · {exam?.domain}
            </div>
            <h2 className="text-xl font-bold text-gray-900">{exam?.title}</h2>
            <p className="text-sm text-gray-600 mt-1">
              Candidate: <span className="font-medium">{result.candidate}</span> ·
              Duration: {Math.floor(result.elapsedSeconds / 60)}m {result.elapsedSeconds % 60}s
            </p>
          </div>
          <div className="text-center">
            <div
              className={`inline-flex items-center justify-center w-20 h-20 rounded-full border-4 text-2xl font-bold ${gradeColor(
                result.percentage,
              )}`}
            >
              {result.band.band}
            </div>
            <div className="text-xs text-gray-500 mt-1">{result.band.label}</div>
          </div>
        </div>

        <div className="mt-5 grid grid-cols-2 sm:grid-cols-4 gap-3 text-center">
          <BigStat label="Score" value={`${result.correctCount}/${result.total}`} />
          <BigStat label="Percentage" value={`${result.percentage}%`} />
          <BigStat
            label="Result"
            value={result.passed ? "PASS" : "FAIL"}
            highlight={result.passed ? "text-green-600" : "text-red-600"}
          />
          <BigStat label="Pass mark" value={`${exam?.passingScore ?? 70}%`} />
        </div>

        <div className="mt-4">
          <div className={`inline-flex px-3 py-1 rounded-full text-sm font-medium border ${gradeColor(result.percentage)}`}>
            {result.passed
              ? result.percentage >= 85
                ? "Recruiter signal: Strong hire — clear command of the discipline."
                : "Recruiter signal: Pass — competent practitioner, probe weaker skills."
              : "Recruiter signal: Below threshold — revisit fundamentals before re-screen."}
          </div>
        </div>
      </Card>

      <Card className="p-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">Skill Breakdown</h3>
        <div className="space-y-3">
          {skills.map(([skill, data]) => (
            <div key={skill}>
              <div className="flex items-center justify-between text-sm mb-1">
                <span className="font-medium text-gray-700 capitalize">{skill.replace(/-/g, " ")}</span>
                <span className="text-gray-500">
                  {data.correct}/{data.total} · {data.pct}%
                </span>
              </div>
              <div className="h-2 bg-gray-100 rounded-full overflow-hidden">
                <div
                  className={`h-full transition-all ${
                    data.pct >= 80 ? "bg-green-500" : data.pct >= 60 ? "bg-indigo-500" : "bg-amber-500"
                  }`}
                  style={{ width: `${data.pct}%` }}
                />
              </div>
            </div>
          ))}
        </div>
      </Card>

      {exam && (
        <Card className="p-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">Answer Review</h3>
          <div className="space-y-4">
            {exam.questions.map((q, idx) => {
              const rec = result.answers.find((r) => r.questionId === q.id);
              const selected = rec?.selected ?? -1;
              return (
                <div key={q.id} className="border border-gray-200 rounded-lg p-4">
                  <div className="flex items-start gap-2">
                    <span
                      className={`mt-0.5 inline-flex items-center justify-center w-6 h-6 rounded-full text-xs font-bold flex-shrink-0 ${
                        rec?.isCorrect ? "bg-green-100 text-green-700" : "bg-red-100 text-red-700"
                      }`}
                    >
                      {rec?.isCorrect ? "✓" : "✗"}
                    </span>
                    <div className="flex-1">
                      <p className="text-sm font-medium text-gray-900">
                        {idx + 1}. {q.prompt}
                      </p>
                      <div className="mt-2 space-y-1 text-sm">
                        {q.options.map((opt, oIdx) => {
                          const isCorrect = oIdx === q.correct;
                          const isSelected = oIdx === selected;
                          return (
                            <div
                              key={oIdx}
                              className={`px-2 py-1 rounded ${
                                isCorrect
                                  ? "bg-green-50 text-green-800"
                                  : isSelected
                                    ? "bg-red-50 text-red-800"
                                    : "text-gray-600"
                              }`}
                            >
                              <span className="font-medium mr-1">
                                {String.fromCharCode(65 + oIdx)}.
                              </span>
                              {opt}
                              {isCorrect && " (correct)"}
                              {isSelected && !isCorrect && " (your answer)"}
                            </div>
                          );
                        })}
                      </div>
                      <p className="mt-2 text-xs text-gray-500 italic">{q.explanation}</p>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </Card>
      )}

      <div className="flex gap-3">
        <Button onClick={onRestart}>Take Another Exam</Button>
        <Button
          variant="outline"
          onClick={() => window.print()}
        >
          Print / Save PDF Report
        </Button>
      </div>
    </div>
  );
}

function Stat({ label, value }: { label: string; value: number | string }) {
  return (
    <div className="bg-gray-50 rounded-lg p-3">
      <div className="text-2xl font-bold text-gray-900">{value}</div>
      <div className="text-xs text-gray-500">{label}</div>
    </div>
  );
}

function MiniStat({ label, value }: { label: string; value: number | string }) {
  return (
    <div className="bg-gray-50 rounded-md p-2">
      <div className="text-sm font-bold text-gray-900">{value}</div>
      <div className="text-[10px] text-gray-500">{label}</div>
    </div>
  );
}

function BigStat({
  label,
  value,
  highlight,
}: {
  label: string;
  value: string;
  highlight?: string;
}) {
  return (
    <div className="bg-gray-50 rounded-lg p-3">
      <div className={`text-xl font-bold ${highlight ?? "text-gray-900"}`}>{value}</div>
      <div className="text-xs text-gray-500">{label}</div>
    </div>
  );
}

