+            </div>
+            <Button className="mt-4 w-full" onClick={() => onPick(exam)}>
+              Start Exam
+            </Button>
+          </Card>
+        ))}
+      </div>
+    </div>
+  );
+}
+
+function ResultView({
+  result,
+  exam,
+  onRestart,
