+            </div>
+            <h2 className="text-xl font-bold text-gray-900">{exam?.title}</h2>
+            <p className="text-sm text-gray-600 mt-1">
+              Candidate: <span className="font-medium">{result.candidate}</span> ·
+              Duration: {Math.floor(result.elapsedSeconds / 60)}m {result.elapsedSeconds % 60}s
+            </p>
+          </div>
+          <div className="text-center">
+            <div
