input.content:
"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import { Card, Button, Badge, Input } from "@/components/marketing/ui";
import {
  EXAMS,
  getExam,
  bandFor,
  type Exam,
  type Question,
} from "@/lib/marketing-tests/exams";

type Phase = "picker" | "running" | "results" | "history";

interface AnswerRecord {
  questionId: string;
  selected: number;
  correct: number;
  skill: string;
  difficulty: number;
  isCorrect: boolean;
}

interface Candidate {
  name: string;
  email: string;
}

interface ExamResult {
  attemptId: string;
  examId: string;
  examTitle: string;
  domain: string;
  score: number;
  total: number;
  correctCount: number;
  percentage: number;
  passed: boolean;
  band: ReturnType<typeof bandFor>;
  skillBreakdown: Record<string, { correct: number; total: number; pct: number }>;
  answers: AnswerRecord[];
  candidate: string;
  email: string;
  elapsedSeconds: number;
  timedOut: boolean;
  takenAt: number;
}

const HISTORY_KEY = "marketing-hub:exam-history";
const CANDIDATE_KEY = "marketing-hub:exam-candidate";

function loadHistory(): ExamResult[] {
  if (typeof window === "undefined") return [];
  try {
    const raw = localStorage.getItem(HISTORY_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw) as ExamResult[];
    if (!Array.isArray(parsed)) return [];
    return parsed;
  } catch {
    return [];
  }
}

function saveHistory(list: ExamResult[]) {
  try {
    localStorage.setItem(HISTORY_KEY, JSON.stringify(list.slice(0, 100)));
  } catch {
    // ignore quota / private mode
  }
}

function loadCandidate(): Candidate {
  if (typeof window === "undefined") return { name: "", email: "" };
  try {
    const raw = localStorage.getItem(CANDIDATE_KEY);
    if (!raw) return { name: "", email: "" };
    const parsed = JSON.parse(raw) as Partial<Candidate>;
    return { name: parsed.name ?? "", email: parsed.email ?? "" };
  } catch {
    return { name: "", email: "" };
  }
}

function saveCandidate(c: Candidate) {
  try {
    localStorage.setItem(CANDIDATE_KEY, JSON.stringify(c));
  } catch {
    // ignore
  }
}

function shuffle<T>(arr: T[]): T[] {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j]!, a[i]!];
  }
  return a;
}

function gradeColor(percentage: number): string {
  if (percentage >= 85) return "bg-green-100 text-green-800 border-green-200";
  if (percentage >= 70) return "bg-blue-100 text-blue-800 border-blue-200";
  if (percentage >= 50) return "bg-amber-100 text-amber-800 border-amber-200";
  return "bg-red-100 text-red-800 border-red-200";
}

function fmtDuration(totalSeconds: number): string {
  const m = Math.floor(totalSeconds / 60);
  const s = totalSeconds % 60;
  return `${m}m ${s.toString().padStart(2, "0")}s`;
}

function fmtCountdown(secondsLeft: number): string {
  if (secondsLeft <= 0) return "0:00";
  const m = Math.floor(secondsLeft / 60);
  const s = secondsLeft % 60;
  return `${m}:${s.toString().padStart(2, "0")}`;
}

export function MarketingTests() {
  const [phase, setPhase] = useState<Phase>("picker");
  const [activeExam, setActiveExam] = useState<Exam | null>(null);
  const [shuffled, setShuffled] = useState<Question[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [answers, setAnswers] = useState<Record<string, number>>({});
  const [candidate, setCandidate] = useState<Candidate>({ name: "", email: "" });
  const [result, setResult] = useState<ExamResult | null>(null);
  const [history, setHistory] = useState<ExamResult[]>([]);
  const [viewingHistory, setViewingHistory] = useState<ExamResult | null>(null);
  const [startTime, setStartTime] = useState(0);
  const [secondsLeft, setSecondsLeft] = useState(0);
  const [timedOut, setTimedOut] = useState(false);

  // hydrate candidate + history on mount
  useEffect(() => {
    setCandidate(loadCandidate());
    setHistory(loadHistory());
  }, []);

  // countdown timer
  const submittedRef = useRef(false);
  useEffect(() => {
    if (phase !== "running" || !activeExam) return;
    submittedRef.current = false;
    const total = activeExam.durationMinutes * 60;
    setSecondsLeft(total);
    const deadline = Date.now() + total * 1000;
    const id = setInterval(() => {
      const left = Math.max(0, Math.round((deadline - Date.now()) / 1000));
      setSecondsLeft(left);
      if (left <= 0 && !submittedRef.current) {
        submittedRef.current = true;
        setTimedOut(true);
        clearInterval(id);
        // auto-submit on expiry
        finishExam(true);
      }
    }, 1000);
    return () => clearInterval(id);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [phase, activeExam]);

  const startExam = (exam: Exam) => {
    if (!candidate.name.trim()) return;
    saveCandidate(candidate);
    setActiveExam(exam);
    setShuffled(shuffle(exam.questions));
    setCurrentIdx(0);
    setAnswers({});
    setResult(null);
    setViewingHistory(null);
    setTimedOut(false);
    setStartTime(Date.now());
    setPhase("running");
  };

  const selectAnswer = (questionId: string, optionIdx: number) => {
    setAnswers((prev) => ({ ...prev, [questionId]: optionIdx }));
  };

  const computeResult = (isTimeout: boolean): ExamResult => {
    if (!activeExam) throw new Error("no active exam");
    const breakdown: Record<string, { correct: number; total: number; pct: number }> = {};
    const records: AnswerRecord[] = [];
    let correctCount = 0;
    for (const q of shuffled) {
      const selected = answers[q.id];
      const isCorrect = selected === q.correct;
      if (isCorrect) correctCount++;
      records.push({
        questionId: q.id,
        selected: selected ?? -1,
        correct: q.correct,
        skill: q.skill,
        difficulty: q.difficulty,
        isCorrect,
      });
      if (!breakdown[q.skill]) breakdown[q.skill] = { correct: 0, total: 0, pct: 0 };
      breakdown[q.skill]!.total += 1;
      if (isCorrect) breakdown[q.skill]!.correct += 1;
    }
    for (const k of Object.keys(breakdown)) {
      const b = breakdown[k]!;
      b.pct = Math.round((b.correct / b.total) * 100);
    }
    const total = shuffled.length;
    const percentage = Math.round((correctCount / total) * 100);
    return {
      attemptId: `${activeExam.id}-${Date.now()}`,
      examId: activeExam.id,
      examTitle: activeExam.title,
      domain: activeExam.domain,
      score: correctCount,
      total,
      correctCount,
      percentage,
      passed: percentage >= activeExam.passingScore,
      band: bandFor(percentage),
      skillBreakdown: breakdown,
      answers: records,
      candidate: candidate.name.trim(),
      email: candidate.email.trim(),
      elapsedSeconds: Math.round((Date.now() - startTime) / 1000),
      timedOut: isTimeout,
      takenAt: Date.now(),
    };
  };

  const finishExam = (isTimeout: boolean) => {
    submittedRef.current = true;
    const r = computeResult(isTimeout);
    setResult(r);
    const next = [r, ...history].slice(0, 100);
    setHistory(next);
    saveHistory(next);
    setPhase("results");
  };

  const submitExam = () => finishExam(false);

  const restart = () => {
    setPhase("picker");
    setActiveExam(null);
    setShuffled([]);
    setAnswers({});
    setResult(null);
    setViewingHistory(null);
    setTimedOut(false);
  };

  const clearHistory = () => {
    setHistory([]);
    saveHistory([]);
  };

  const viewHistoryItem = (item: ExamResult) => {
    setViewingHistory(item);
    setPhase("results");
  };

  const answeredCount = Object.keys(answers).length;
  const allAnswered = activeExam ? answeredCount >= shuffled.length : false;

  if (phase === "picker") {
    return (
      <ExamPicker
        onPick={startExam}
        candidate={candidate}
        setCandidate={setCandidate}
        history={history}
        onViewHistory={(item) => viewHistoryItem(item)}
        onShowHistory={() => setPhase("history")}
        onClearHistory={clearHistory}
      />
    );
  }

  if (phase === "history") {
    return (
      <HistoryView
        history={history}
        onView={(item) => viewHistoryItem(item)}
        onBack={() => setPhase("picker")}
        onClear={clearHistory}
      />
    );
  }

  if (phase === "results") {
    const r = viewingHistory ?? result;
    if (r) {
      return (
        <ResultView
          result={r}
          exam={getExam(r.examId)}
          onRestart={restart}
          isHistorical={!!viewingHistory}
        />
      );
    }
  }

  if (!activeExam) return null;
  const q = shuffled[currentIdx]!;
  const selected = answers[q.id];
  const progress = Math.round((answeredCount / shuffled.length) * 100);
  const lowTime = secondsLeft <= 60;
  const totalSeconds = activeExam.durationMinutes * 60;

  return (
    <div className="space-y-6">
      <Card className="p-6">
        <div className="flex items-center justify-between flex-wrap gap-3">
          <div>
            <div className="flex items-center gap-2">
              <h2 className="text-xl font-bold text-gray-900">{activeExam.title}</h2>
              <Badge variant="secondary">{activeExam.level}</Badge>
            </div>
            <p className="text-sm text-gray-500 mt-1">
              Question {currentIdx + 1} of {shuffled.length} · {answeredCount}/{shuffled.length} answered
              {timedOut && <span className="text-red-600 font-medium"> · Time expired — auto-submitted</span>}
            </p>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-center">
              <div className="text-xs text-gray-500">Time left</div>
              <div
                className={`text-lg font-bold tabular-nums ${lowTime ? "text-red-600" : "text-gray-900"}`}
              >
                {fmtCountdown(secondsLeft)}
              </div>
            </div>
            <div className="text-center">
              <div className="text-xs text-gray-500">Pass mark</div>
              <div className="text-lg font-bold text-gray-900">{activeExam.passingScore}%</div>
            </div>
          </div>
        </div>
        <div className="mt-4 h-2 bg-gray-100 rounded-full overflow-hidden">
          <div
            className="h-full bg-indigo-600 transition-all"
            style={{ width: `${progress}%` }}
          />
        </div>
        <div className="mt-2 h-1 bg-gray-100 rounded-full overflow-hidden">
          <div
            className={`h-full transition-all ${lowTime ? "bg-red-500" : "bg-gray-400"}`}
            style={{ width: `${(secondsLeft / totalSeconds) * 100}%` }}
          />
        </div>
      </Card>

      <Card className="p-6">
        <div className="mb-3 flex items-center gap-2">
          <Badge variant="outline">{activeExam.domain}</Badge>
          <Badge variant="secondary">Skill: {q.skill}</Badge>
          <Badge variant="outline">
            {q.difficulty === 1 ? "Easy" : q.difficulty === 2 ? "Medium" : "Hard"}
          </Badge>
        </div>
        <p className="text-lg font-semibold text-gray-900 mb-4">{q.prompt}</p>
        <div className="space-y-2">
          {q.options.map((opt, idx) => {
            const active = selected === idx;
            return (
              <button
                key={idx}
                onClick={() => selectAnswer(q.id, idx)}
                disabled={timedOut}
                className={`w-full text-left p-3 rounded-lg border transition-colors ${
                  active
                    ? "border-indigo-500 bg-indigo-50"
                    : "border-gray-200 hover:border-indigo-300 hover:bg-gray-50"
                } ${timedOut ? "opacity-60 cursor-not-allowed" : ""}`}
              >
                <span className="font-medium mr-2 text-indigo-600">
                  {String.fromCharCode(65 + idx)}.
                </span>
                <span className="text-sm text-gray-800">{opt}</span>
              </button>
            );
          })}
        </div>
      </Card>

      <div className="flex items-center justify-between flex-wrap gap-3">
        <Button
          variant="outline"
          onClick={() => setCurrentIdx((i) => Math.max(0, i - 1))}
          disabled={currentIdx === 0 || timedOut}
        >
          Previous
        </Button>
        <div className="flex gap-1 flex-wrap max-w-full">
          {shuffled.map((sq, idx) => {
            const answered = answers[sq.id] !== undefined;
            const isCurrent = idx === currentIdx;
            return (
              <button
                key={sq.id}
                onClick={() => setCurrentIdx(idx)}
                disabled={timedOut}
                className={`w-8 h-8 rounded-md text-xs font-medium transition-colors ${
                  isCurrent
                    ? "bg-indigo-600 text-white"
                    : answered
                      ? "bg-indigo-100 text-indigo-700"
                      : "bg-gray-100 text-gray-500 hover:bg-gray-200"
                } ${timedOut ? "cursor-not-allowed" : ""}`}
                aria-label={`Go to question ${idx + 1}`}
              >
                {idx + 1}
              </button>
            );
          })}
        </div>
        {currentIdx < shuffled.length - 1 ? (
          <Button
            onClick={() => setCurrentIdx((i) => Math.min(shuffled.length - 1, i + 1))}
            disabled={timedOut}
          >
            Next
          </Button>
        ) : (
          <Button onClick={submitExam} disabled={!allAnswered || timedOut}>
            {allAnswered ? "Submit Exam" : `Answer all (${answeredCount}/${shuffled.length})`}
          </Button>
        )}
      </div>
    </div>
  );
}

