const [startTime, setStartTime] = useState(0);
const [secondsLeft, setSecondsLeft] = useState(0);
const [timedOut, setTimedOut] = useState(false);

// Refs that mirror the latest state so the timer's auto-submit closure
// never reads stale answers/history (the interval effect only re-runs on
// phase/exam change, so it would otherwise capture the initial empty state).
const answersRef = useRef(answers);
const shuffledRef = useRef(shuffled);
const candidateRef = useRef(candidate);
const startTimeRef = useRef(startTime);
const historyRef = useRef(history);
const activeExamRef = useRef(activeExam);
useEffect(() => { answersRef.current = answers; }, [answers]);
useEffect(() => { shuffledRef.current = shuffled; }, [shuffled]);
useEffect(() => { candidateRef.current = candidate; }, [candidate]);
useEffect(() => { startTimeRef.current = startTime; }, [startTime]);
useEffect(() => { historyRef.current = history; }, [history]);
useEffect(() => { activeExamRef.current = activeExam; }, [activeExam]);

// hydrate candidate + history on mount
useEffect(() => {
  setCandidate(loadCandidate());
  setHistory(loadHistory());
}, []);

// countdown timer
const submittedRef = useRef(false);
useEffect(() => {
  if (phase !== "running" || !activeExam) return;
  submittedRef.current = false;
  const total = activeExam.durationMinutes * 60;
  setSecondsLeft(total);
  const deadline = Date.now() + total * 1000;
  const id = setInterval(() => {
    const left = Math.max(0, Math.round((deadline - Date.now()) / 1000));
    setSecondsLeft(left);
    if (left <= 0 && !submittedRef.current) {
      submittedRef.current = true;
      setTimedOut(true);
      clearInterval(id);
      // auto-submit on expiry — reads latest state via refs
      finishExam(true);
    }
  }, 1000);
  return () => clearInterval(id);
  // eslint-disable-next-line react-hooks/exhaustive-deps
}, [phase, activeExam]);

