  if (allScores.length === 0) return 0;
  let below = 0;
  let equal = 0;
  for (const s of allScores) {
    if (s < score) below++;
    else if (s === score) equal++;
  }
  return Math.round(((below + 0.5 * equal) / allScores.length) * 100);
}

