    const suggestedExams = EXAMS
      .filter((e) => e.questions.some((q) => q.skill === skill))
      .map((e) => e.id);
    let recommendation: string;
    if (data.pct >= 85) {
      recommendation = "Maintain — mastery demonstrated; consider mentoring others.";
    } else if (data.pct >= 70) {
