// Per-question timing: accumulate ms spent on the current question.
// qStartRef tracks when the current question became active; a 500ms interval
// flushes the delta into questionTimingsRef so auto-submit captures it.
useEffect(() => {
  if (phase !== "running") return;
  qStartRef.current = Date.now();
  const id = setInterval(() => {
    const q = shuffledRef.current[currentIdxRef.current];
    if (!q) return;
    const delta = Date.now() - qStartRef.current;
    qStartRef.current = Date.now();
    questionTimingsRef.current = {
      ...questionTimingsRef.current,
      [q.id]: (questionTimingsRef.current[q.id] ?? 0) + delta,
    };
    setQuestionTimings(questionTimingsRef.current);
  }, 500);
  return () => clearInterval(id);
}, [phase]);

// Fullscreen proctor mode: request fullscreen on exam start, track exits.
useEffect(() => {
  if (phase !== "running") return;
  const onFsChange = () => {
    if (!document.fullscreenElement) {
      setFullscreenExits((n) => n + 1);
      fullscreenExitsRef.current += 1;
    }
  };
  document.addEventListener("fullscreenchange", onFsChange);
  return () => document.removeEventListener("fullscreenchange", onFsChange);
}, [phase]);

