const startExam = (exam: Exam) => {
  if (!candidate.name.trim()) return;
  saveCandidate(candidate);
  // Pre-compute option shuffles for anti-cheat (randomize option order).
  const shuffleMap = new Map<string, { options: string[]; indexMap: number[] }>();
  for (const q of exam.questions) {
    shuffleMap.set(q.id, shuffleOptions(q));
  }
  optionShuffleRef.current = shuffleMap;
  // Request fullscreen proctor mode (best-effort; continue if denied).
  try {
    document.documentElement.requestFullscreen?.().catch(() => { /* user denied — continue */ });
  } catch { /* ignore */ }
  setActiveExam(exam);
  setShuffled(shuffle(exam.questions));
  setCurrentIdx(0);
  setAnswers({});
  setResult(null);
  setViewingHistory(null);
  setTimedOut(false);
  setTabSwitches(0);
  tabSwitchesRef.current = 0;
  setFullscreenExits(0);
  fullscreenExitsRef.current = 0;
  setQuestionTimings({});
  questionTimingsRef.current = {};
  qStartRef.current = Date.now();
  setStartTime(Date.now());
  setPhase("running");
};

