function exportCertificatePdf(result: ExamResult) {
  const doc = new jsPDF({ orientation: "landscape", unit: "mm", format: "a4" });
  const certId = certificateId(result.examId, result.candidate, result.takenAt);
  const pageW = doc.internal.pageSize.getWidth();
  const pageH = doc.internal.pageSize.getHeight();
  const cx = pageW / 2;

  // Border
  doc.setDrawColor(99, 102, 241);
  doc.setLineWidth(1.5);
  doc.rect(10, 10, pageW - 20, pageH - 20);

  // Inner border
  doc.setLineWidth(0.5);
  doc.rect(14, 14, pageW - 28, pageH - 28);

  // Header
  doc.setFont("helvetica", "bold");
  doc.setFontSize(22);
  doc.setTextColor(99, 102, 241);
  doc.text("Marketing Hub", cx, 35, { align: "center" });
  doc.setFontSize(14);
  doc.setTextColor(107, 114, 128);
  doc.text("Certification Authority", cx, 43, { align: "center" });

  // Seal
  doc.setFontSize(40);
  doc.setTextColor(250, 204, 21);
  doc.text("\u2605", cx, 68, { align: "center" });

  // Title
  doc.setFont("helvetica", "bold");
  doc.setFontSize(18);
  doc.setTextColor(31, 41, 55);
  doc.text("Certificate of Achievement", cx, 82, { align: "center" });

  // Statement
  doc.setFont("helvetica", "normal");
  doc.setFontSize(12);
  doc.setTextColor(55, 65, 81);
  doc.text("This is to certify that", cx, 95, { align: "center" });

  doc.setFont("helvetica", "bold");
  doc.setFontSize(16);
  doc.setTextColor(31, 41, 55);
  doc.text(result.candidate, cx, 105, { align: "center" });

  doc.setFont("helvetica", "normal");
  doc.setFontSize(12);
  doc.setTextColor(55, 65, 81);
  doc.text("has successfully completed the", cx, 115, { align: "center" });

  doc.setFont("helvetica", "bold");
  doc.setFontSize(14);
  doc.setTextColor(31, 41, 55);
  doc.text(result.examTitle, cx, 123, { align: "center" });

  doc.setFont("helvetica", "normal");
  doc.setFontSize(12);
  doc.setTextColor(55, 65, 81);
  doc.text(
    `with a grade of ${result.band.band} (${result.percentage}%)`,
    cx,
    133,
    { align: "center" },
  );

  // Metadata
  const metaY = 150;
  doc.setFontSize(10);
  doc.setTextColor(107, 114, 128);
  const dateStr = new Date(result.takenAt).toLocaleDateString();
  doc.text(`Date: ${dateStr}`, 40, metaY);
  doc.text(`Duration: ${fmtDuration(result.elapsedSeconds)}`, pageW / 2, metaY, { align: "center" });
  doc.text(`Tab switches: ${result.tabSwitches}`, pageW - 40, metaY, { align: "right" });

  // Certificate ID
  doc.setFont("helvetica", "bold");
  doc.setFontSize(11);
  doc.setTextColor(31, 41, 55);
  doc.text("Certificate ID:", cx, metaY + 15, { align: "center" });
  doc.setFont("courier", "normal");
  doc.setFontSize(13);
  doc.setTextColor(99, 102, 241);
  doc.text(certId, cx, metaY + 22, { align: "center" });

  // Signature line
  doc.setDrawColor(156, 163, 175);
  doc.setLineWidth(0.3);
  doc.line(40, pageH - 30, 90, pageH - 30);
  doc.line(pageW - 90, pageH - 30, pageW - 40, pageH - 30);
  doc.setFont("helvetica", "normal");
  doc.setFontSize(9);
  doc.setTextColor(107, 114, 128);
  doc.text("Issuing Authority", 65, pageH - 25, { align: "center" });
  doc.text("Candidate Signature", pageW - 65, pageH - 25, { align: "center" });

  // Footer
  doc.setFontSize(8);
  doc.setTextColor(156, 163, 175);
  doc.text(
    `Issued ${dateStr} · Marketing Hub Recruiting Authority · Void if altered`,
    cx,
    pageH - 15,
    { align: "center" },
  );

  doc.save(`certificate-${result.candidate.replace(/\s+/g, "-").toLowerCase()}.pdf`);
}

